package org.apache.commons.csv;
import java.io.Closeable;
import java.io.File;
import java.io.FileInputStream;
import java.io.FileReader;
import java.io.InputStreamReader;
import java.io.StringReader;
import java.net.URL;
import java.nio.charset.Charset;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collection;
import java.util.Iterator;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.NoSuchElementException;
import static org.apache.commons.csv.Token.Type.*;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.lang.reflect.InvocationTargetException;
import java.util.Map;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    private Reader mockReader;
    private CSVFormat mockFormat;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        mockFormat = mock(CSVFormat.class);
    }

    @Test
    void testConstructor_NullReader_ThrowsException() {
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> new CSVParser(null, mockFormat));
        assertEquals("reader", ex.getMessage());
    }

    @Test
    void testConstructor_NullFormat_ThrowsException() {
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> new CSVParser(mockReader, null));
        assertEquals("format", ex.getMessage());
    }

    @Test
    void testConstructor_InitializesFields() throws Exception {
        // Mock Assertions.notNull to throw NullPointerException on null argument
        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            assertionsMockedStatic.when(() -> Assertions.notNull(any(), any()))
                    .thenAnswer(invocation -> {
                        Object arg = invocation.getArgument(0);
                        String name = invocation.getArgument(1);
                        if (arg == null) {
                            throw new NullPointerException(name);
                        }
                        return null;
                    });

            // Mock ExtendedBufferedReader constructor to return a mock
            try (MockedConstruction<ExtendedBufferedReader> mockedBufferedReader = Mockito.mockConstruction(ExtendedBufferedReader.class)) {
                // Mock Lexer constructor to return a mock
                try (MockedConstruction<Lexer> mockedLexer = Mockito.mockConstruction(Lexer.class)) {
                    CSVParser parser = new CSVParser(mockReader, mockFormat);

                    // Verify format field set correctly
                    Field formatField = CSVParser.class.getDeclaredField("format");
                    formatField.setAccessible(true);
                    assertSame(mockFormat, formatField.get(parser));

                    // Verify lexer field initialized with mocked Lexer
                    Field lexerField = CSVParser.class.getDeclaredField("lexer");
                    lexerField.setAccessible(true);
                    Lexer lexer = (Lexer) lexerField.get(parser);
                    assertNotNull(lexer);

                    // Verify headerMap field initialized by calling initializeHeader()
                    Field headerMapField = CSVParser.class.getDeclaredField("headerMap");
                    headerMapField.setAccessible(true);
                    Map<String, Integer> headerMap = (Map<String, Integer>) headerMapField.get(parser);
                    assertNotNull(headerMap);

                    // Verify that ExtendedBufferedReader was constructed with the mockReader
                    assertEquals(1, mockedBufferedReader.constructed().size());
                    ExtendedBufferedReader extendedBufferedReader = mockedBufferedReader.constructed().get(0);
                    // No direct way to verify argument passed to constructor, but construction count is checked

                    // Verify Lexer was constructed with format and ExtendedBufferedReader mock
                    assertEquals(1, mockedLexer.constructed().size());
                }
            }
        }
    }
}
